def validate_rq_candidate(rqc, known_axes):
    problems = []

    # C-TOTALITY: ensure rqc is a dict
    if not isinstance(rqc, dict):
        return {"ok": False, "problems": ["rqc must be a dict"]}

    # Q1: Check all required fields are present
    required_fields = ['rq_candidate_id', 'question', 'derived_from_axes', 'decision_relevance', 'priority', 'rdec_refs']
    for field in required_fields:
        if field not in rqc:
            problems.append(f"Missing required field: {field}")

    if problems:
        return {"ok": False, "problems": problems}

    # Q2: derived_from_axes must be a non-empty list and all elements in known_axes
    derived_from_axes = rqc['derived_from_axes']
    if not isinstance(derived_from_axes, list):
        problems.append("derived_from_axes must be a list")
    elif len(derived_from_axes) == 0:
        problems.append("derived_from_axes must be a non-empty list")
    else:
        for axis_id in derived_from_axes:
            if not isinstance(axis_id, str):
                problems.append(f"derived_from_axes element {axis_id} must be a string")
            elif axis_id not in known_axes:
                problems.append(f"derived_from_axes contains unknown axis id: {axis_id}")

    # Q3: decision_relevance must be a non-empty string
    decision_relevance = rqc['decision_relevance']
    if not isinstance(decision_relevance, str) or len(decision_relevance) == 0:
        problems.append("decision_relevance must be a non-empty string")

    # Q4: priority must be one of REQUIRED, OPTIONAL, DEFERRED
    priority = rqc['priority']
    valid_priorities = ['REQUIRED', 'OPTIONAL', 'DEFERRED']
    if priority not in valid_priorities:
        problems.append(f"priority must be one of {valid_priorities}")

    # Q5: if priority is 'REQUIRED', rdec_refs must be a non-empty list
    if priority == 'REQUIRED':
        rdec_refs = rqc['rdec_refs']
        if not isinstance(rdec_refs, list):
            problems.append("rdec_refs must be a list when priority is REQUIRED")
        elif len(rdec_refs) == 0:
            problems.append("rdec_refs must be a non-empty list when priority is REQUIRED")
        else:
            # Validate contents of rdec_refs are strings
            for ref in rdec_refs:
                if not isinstance(ref, str):
                    problems.append(f"rdec_refs element {ref} must be a string")

    # Additional type validations for other fields (addressing audit concerns)
    # Q1: rq_candidate_id must be a string
    rq_candidate_id = rqc['rq_candidate_id']
    if not isinstance(rq_candidate_id, str):
        problems.append("rq_candidate_id must be a string")

    # Q1: question must be a string
    question = rqc['question']
    if not isinstance(question, str):
        problems.append("question must be a string")

    # Q1: rdec_refs must be a list (when priority is not REQUIRED)
    if priority != 'REQUIRED':
        rdec_refs = rqc['rdec_refs']
        if not isinstance(rdec_refs, list):
            problems.append("rdec_refs must be a list")

    return {"ok": len(problems) == 0, "problems": problems}
